import * as React from 'react';
import { render } from '@testing-library/react';
import { Image_unstable as Image } from './Image';

describe('Image', () => {
  test.each([undefined, 'contain', 'none', 'cover', 'center', 'default'] as const)('fit: %s', fit => {
    const wrapper = render(<Image fit={fit} />);
    expect(wrapper.container).toMatchSnapshot();
  });
});
